use askama::Template;
use axum::extract::State;
use axum::http::StatusCode;
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;

use crate::domain::{EmailValidationError, PasswordError};
use crate::services::registration::{register_user, RegistrationError};

#[derive(Template)]
#[template(path = "register.html")]
pub struct RegisterTemplate {
    pub general_error: Option<String>,
    pub form_email: String,
    pub email_error: Option<String>,
    pub password_error: Option<String>,
    pub password_confirmation_error: Option<String>,
}

pub async fn get_register() -> Result<impl IntoResponse, RegisterError> {
    let template = RegisterTemplate {
        general_error: None,
        form_email: String::new(),
        email_error: None,
        password_error: None,
        password_confirmation_error: None,
    };
    Ok(Html(template.render()?))
}

#[derive(serde::Deserialize)]
pub struct RegisterFormData {
    pub email: String,
    pub password: String,
    pub password_confirmation: String,
}

pub async fn post_register(
    State(pool): State<PgPool>,
    Form(form): Form<RegisterFormData>,
) -> Result<Response, RegisterError> {
    match register_user(
        &pool,
        form.email.clone(),
        form.password,
        form.password_confirmation,
    )
    .await
    {
        Ok(_user_id) => Ok(Redirect::to("/todos").into_response()),
        Err(e) => {
            let mut template = RegisterTemplate {
                general_error: None,
                form_email: form.email,
                email_error: None,
                password_error: None,
                password_confirmation_error: None,
            };

            match &e {
                RegistrationError::InvalidEmail(email_err) => {
                    template.email_error = Some(user_facing_email_error(email_err));
                }
                RegistrationError::InvalidPassword(pwd_err) => {
                    template.password_error = Some(user_facing_password_error(pwd_err));
                }
                RegistrationError::PasswordMismatch => {
                    template.password_confirmation_error =
                        Some("Passwords do not match".to_string());
                }
                RegistrationError::DuplicateEmail => {
                    template.general_error = Some(
                        "Unable to create account. If you already have an account, try <a href=\"/login\">signing in</a>.".to_string()
                    );
                }
                RegistrationError::Unexpected(err) => {
                    tracing::error!(error = ?err, "Unexpected registration error");
                    template.general_error =
                        Some("Something went wrong. Please try again.".to_string());
                }
            }

            let body = template.render().map_err(RegisterError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
    }
}

fn user_facing_email_error(err: &EmailValidationError) -> String {
    match err {
        EmailValidationError::Empty => "Enter your email address".to_string(),
        EmailValidationError::MissingAtSymbol => {
            "Enter a valid email address, like name@example.com".to_string()
        }
        EmailValidationError::TooLong => "That email address is too long".to_string(),
    }
}

fn user_facing_password_error(err: &PasswordError) -> String {
    match err {
        PasswordError::Empty => "Enter a password".to_string(),
        PasswordError::TooShort => "Your password needs at least 8 characters".to_string(),
        PasswordError::TooLong => "That password is too long".to_string(),
    }
}

#[derive(Debug, thiserror::Error)]
pub enum RegisterError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
}

impl IntoResponse for RegisterError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Registration template rendering failed");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

use crate::helpers::spawn_app;

#[tokio::test]
async fn get_register_returns_200_with_registration_form() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/register", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let content_type = response
        .headers()
        .get("content-type")
        .expect("Missing content-type header")
        .to_str()
        .unwrap();
    assert!(
        content_type.contains("text/html"),
        "Expected text/html, got {content_type}"
    );

    let body = response.text().await.unwrap();

    // Page structure
    assert!(body.contains("Create account"), "Missing page heading");
    assert!(
        body.contains("Create account -- Todo List"),
        "Missing descriptive page title"
    );

    // Form fields with labels
    assert!(
        body.contains("<label for=\"email\">Email</label>"),
        "Missing email label"
    );
    assert!(body.contains("type=\"email\""), "Missing email input");
    assert!(
        body.contains("<label for=\"password\">Password</label>"),
        "Missing password label"
    );
    assert!(
        body.contains("autocomplete=\"new-password\""),
        "Missing autocomplete=\"new-password\" on password fields"
    );
    assert!(
        body.contains("<label for=\"password_confirmation\">Confirm password</label>"),
        "Missing password confirmation label"
    );

    // Submit button with action words
    assert!(
        body.contains(">Create account</button>"),
        "Submit button should say 'Create account'"
    );

    // Link to login
    assert!(body.contains("Sign in"), "Missing link to login page");
    assert!(body.contains("href=\"/login\""), "Missing login link href");

    // Accessibility: no error states on initial load
    assert!(
        !body.contains("aria-invalid=\"true\""),
        "Should not have aria-invalid=\"true\" on initial load"
    );
    // Error containers exist (for aria-describedby targets) but should be empty
    assert!(
        !body.contains("Enter your email address"),
        "Should not show email error text on initial load"
    );
    assert!(
        !body.contains("at least 8 characters</p>"),
        "Should not show password error text on initial load"
    );
}

#[tokio::test]
async fn post_register_with_valid_data_redirects() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "test@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Expected 303 See Other redirect after successful registration"
    );
}

#[tokio::test]
async fn post_register_persists_user_in_database() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "persist@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    let saved = sqlx::query!(
        "SELECT email, password_hash FROM users WHERE email = $1",
        "persist@example.com"
    )
    .fetch_one(&app.pool)
    .await
    .expect("Failed to fetch saved user");

    assert_eq!(saved.email, "persist@example.com");
    assert!(
        saved.password_hash.starts_with("$argon2"),
        "Password should be hashed with Argon2"
    );
}

#[tokio::test]
async fn post_register_returns_422_when_email_is_empty() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", ""),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(
        body.contains("Enter your email address"),
        "Should show email error message"
    );
}

#[tokio::test]
async fn post_register_returns_422_when_email_is_invalid() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "notanemail"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(
        body.contains("name@example.com"),
        "Should show email format hint"
    );
}

#[tokio::test]
async fn post_register_returns_422_when_password_too_short() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "test@example.com"),
